/**
 * webpack tools for building dynamic plugin assets.
 *
 * @remarks
 * This package allows building dynamic plugins with webpack based on the concept
 * of {@link https://webpack.js.org/concepts/module-federation/ | module federation}.
 *
 * @packageDocumentation
 */

import type { Compiler } from 'webpack';
import type { container } from 'webpack';
import type { WebpackPluginInstance } from 'webpack';

/**
 * The type `{}` doesn't mean "any empty object", it means "any non-nullish value".
 *
 * Use the `AnyObject` type for objects whose structure is unknown.
 *
 * @see https://github.com/typescript-eslint/typescript-eslint/issues/2063#issuecomment-675156492
 */
export declare type AnyObject = Record<string, unknown>;

/**
 * Code reference, represented as an async function that returns the expected value.
 */
export declare type CodeRef<TValue = unknown> = () => Promise<TValue>;

export declare type CodeRefsToEncodedCodeRefs<T> = T extends CodeRef ? EncodedCodeRef : T extends (infer U)[] ? CodeRefsToEncodedCodeRefs<U>[] : T extends object ? MapCodeRefsToEncodedCodeRefs<T> : T;

export declare class DynamicRemotePlugin implements WebpackPluginInstance {
    private readonly adaptedOptions;
    constructor(options: DynamicRemotePluginOptions);
    apply(compiler: Compiler): void;
}

export declare type DynamicRemotePluginOptions = {
    /**
     * Plugin build metadata.
     */
    pluginMetadata: PluginBuildMetadata;
    /**
     * List of extensions contributed by the plugin.
     */
    extensions: EncodedExtension[];
    /**
     * Modules shared between the host application and its plugins at runtime.
     *
     * It is the host application's responsibility to initialize and maintain its shared
     * scope object, and to communicate information on application provided modules to its
     * plugins.
     *
     * Default value: empty object.
     */
    sharedModules?: WebpackSharedObject;
    /**
     * Customize the webpack `ModuleFederationPlugin` options.
     */
    moduleFederationSettings?: PluginModuleFederationSettings;
    /**
     * Customize the call to global callback function in the plugin entry script.
     *
     * This option applies only if the module federation library type is `jsonp`.
     */
    entryCallbackSettings?: PluginEntryCallbackSettings;
    /**
     * Customize the filename of the generated plugin entry script.
     *
     * We recommend using `[contenthash]` or `[fullhash]` placeholder in production builds,
     * e.g. `plugin-entry.[contenthash].min.js`.
     *
     * Default value: `plugin-entry.js`.
     *
     * @see https://webpack.js.org/configuration/output/#outputfilename
     */
    entryScriptFilename?: string;
    /**
     * Customize the filename of the generated plugin manifest.
     *
     * Default value: `plugin-manifest.json`.
     */
    pluginManifestFilename?: string;
    /**
     * Transform the plugin manifest before emitting the asset to webpack compilation.
     *
     * By default, no transformation is performed on the manifest.
     */
    transformPluginManifest?: (manifest: RemotePluginManifest) => RemotePluginManifest;
};

/**
 * Code reference, encoded as an object literal for JSON serialization purposes.
 *
 * The value of `$codeRef` property should be formatted as either `moduleName.exportName`
 * (refers to the module's named export) or `moduleName` (refers to the module's `default`
 * export).
 */
export declare type EncodedCodeRef = {
    $codeRef: string;
};

/**
 * Modify `TExtension` type by replacing `CodeRef` property values with `EncodedCodeRef` values.
 */
export declare type EncodedExtension<TExtension extends Extension = Extension> = ReplaceProperties<TExtension, {
    properties: ReplaceProperties<ExtractExtensionProperties<TExtension>, MapCodeRefsToEncodedCodeRefs<ExtractExtensionProperties<TExtension>>>;
}>;

/**
 * An extension of your application.
 *
 * Each extension instance extends the application's functionality in a specific way.
 * A plugin consists of one or more extension instances that, combined together, adapt
 * or extend the base application's functionality.
 *
 * The `type` property determines the kind of the extension, while the `properties`
 * object contains data and/or code necessary to interpret the given extension type.
 *
 * We recommend using a structured extension type format, for example:
 * ```js
 * app.page/route // adds new route that renders the given page component
 * app.page/resource/list // adds new list page for the given resource
 * app.page/resource/details // adds new details page for the given resource
 * ```
 *
 * The `properties` object may contain code references represented as {@link CodeRef}
 * values. Each code reference should be resolved (e.g. referenced value loaded over
 * the network via `import()` function) only when needed. Therefore, any code reference
 * resolution errors should be handled as part of interpreting the given extension type.
 *
 * Extensions may also use feature flags to express condition(s) of their enablement.
 *
 * @see {@link ExtensionFlags}
 */
export declare type Extension<TType extends string = string, TProperties extends AnyObject = AnyObject> = {
    type: TType;
    properties: TProperties;
    flags?: ExtensionFlags;
    [customProperty: string]: unknown;
};

/**
 * An extension's feature flag requirements.
 *
 * In order for an extension to be in use:
 * - for every flag name in `required` list - flag value must be `true`
 * - for every flag name in `disallowed` list - flag value must be `false` or `undefined`
 */
export declare type ExtensionFlags = Partial<{
    required: string[];
    disallowed: string[];
}>;

/**
 * Infer the properties type from extension type `T`.
 */
export declare type ExtractExtensionProperties<T> = T extends Extension<any, infer TProperties> ? TProperties : never;

export declare type MapCodeRefsToEncodedCodeRefs<T extends object> = {
    [K in keyof T]: CodeRefsToEncodedCodeRefs<T[K]>;
};

export declare type PluginBuildMetadata = PluginRuntimeMetadata & {
    exposedModules?: {
        [moduleName: string]: string;
    };
};

/**
 * This interface can be extended by the host application to type the
 * {@link PluginRuntimeMetadata.customProperties} object to reflect supported
 * application or environment specific properties.
 *
 * @example
 * ```
 * // in your d.ts declaration file
 * import type { SupportedCustomProperties } from './types';
 *
 * declare module '@openshift/dynamic-plugin-sdk' {
 *   interface PluginCustomProperties extends SupportedCustomProperties {}
 * }
 * ```
 */
export declare interface PluginCustomProperties {
}

/**
 * Settings for the global callback function used by plugin entry scripts.
 */
export declare type PluginEntryCallbackSettings = Partial<{
    /**
     * Name of the callback function.
     *
     * Default value: `__load_plugin_entry__`.
     */
    name: string;
    /**
     * Plugin identifier, passed as the first argument.
     *
     * Default value: plugin name, as specified in the plugin metadata.
     */
    pluginID: string;
}>;

/**
 * Settings for the webpack `ModuleFederationPlugin`.
 */
export declare type PluginModuleFederationSettings = Partial<{
    /**
     * Configure how the plugin entry module will be exposed at runtime.
     *
     * This value is passed to `ModuleFederationPlugin` as `library.type`.
     *
     * Note that `library.name` will be set to the name of the plugin.
     *
     * Default value: `jsonp`.
     *
     * @see https://webpack.js.org/configuration/output/#outputlibrarytype
     */
    libraryType: string;
    /**
     * The name of webpack share scope object used to share modules between the host
     * application and its plugins.
     *
     * This option applies only if the target host application is built with webpack
     * and uses dedicated webpack specific APIs such as `__webpack_init_sharing__`
     * and `__webpack_share_scopes__` to initialize and access this object.
     *
     * If the target host application is not built with webpack, plugins will not be
     * able to contribute new modules into the share scope object; however, plugins
     * will still be able to use any application provided shared modules.
     *
     * Default value: `default`.
     *
     * @see https://webpack.js.org/plugins/module-federation-plugin/#sharescope
     */
    sharedScopeName: string;
    /**
     * Override the implementation of core webpack module federation plugin(s) to use
     * for the webpack build.
     *
     * If not specified, standard webpack provided implementation of the given plugin
     * will be used.
     *
     * @see https://github.com/module-federation/universe/tree/main/packages/enhanced
     */
    pluginOverride: Partial<{
        /**
         * Custom `ModuleFederationPlugin` implementation.
         */
        ModuleFederationPlugin: typeof container.ModuleFederationPlugin;
        /**
         * Custom `ContainerPlugin` implementation.
         */
        ContainerPlugin: typeof container.ContainerPlugin;
    }>;
}>;

/**
 * Runtime plugin metadata.
 *
 * There can be only one plugin with the given `name` loaded at any time.
 *
 * Any dependencies on other plugins will be resolved as part of the plugin's load process.
 *
 * The `customProperties` object may contain additional information to be interpreted by the host
 * application. We recommend scoping related application or environment specific properties under
 * the same key, for example:
 *
 * ```js
 * customProperties: {
 *   sampleApp: {
 *     // Custom properties supported by the sample application
 *   }
 * }
 * ```
 */
export declare type PluginRuntimeMetadata = {
    name: string;
    version: string;
    dependencies?: Record<string, string>;
    optionalDependencies?: Record<string, string>;
    customProperties?: PluginCustomProperties;
};

/**
 * Plugin manifest generated as part of the plugin's webpack build.
 *
 * The `extensions` list contains all extensions contributed by the plugin. Code references
 * within each extension's properties are serialized as JSON objects `{ $codeRef: string }`.
 *
 * The `baseURL` should be used when loading all plugin assets, including the ones listed
 * in `loadScripts`.
 *
 * This is the standard representation of a plugin manifest; we load the specified scripts
 * from remote sources in order to initialize the plugin and provide access to its exposed
 * modules.
 */
export declare type RemotePluginManifest = PluginRuntimeMetadata & {
    baseURL: string;
    extensions: Extension[];
    loadScripts: string[];
    registrationMethod: 'callback' | 'custom';
    buildHash?: string;
};

/**
 * Replace existing direct properties of `T` with ones declared in `R`.
 */
export declare type ReplaceProperties<T, R> = {
    [K in keyof T]: K extends keyof R ? R[K] : T[K];
};

/**
 * webpack `SharedConfig` type.
 *
 * Advanced configuration for modules that should be shared in the share scope.
 *
 * @see https://webpack.js.org/plugins/module-federation-plugin/#sharing-hints
 */
export declare type WebpackSharedConfig = {
    eager?: boolean;
    import?: string | false;
    packageName?: string;
    requiredVersion?: string | false;
    shareKey?: string;
    shareScope?: string;
    singleton?: boolean;
    strictVersion?: boolean;
    version?: string | false;
};

/**
 * webpack `SharedObject` type.
 *
 * Modules that should be shared in the share scope.
 */
export declare type WebpackSharedObject = {
    [index: string]: string | WebpackSharedConfig;
};

export { }
